  <script src="../../../assets/images.nvidia.com/gtc/modernizr.min.js" type="text/javascript"></script> 
  <script id="rendered-js">
    var d = document;
    var wrap = d.querySelector('.wrap');
    var items = d.querySelector('.items');
    var itemCount = d.querySelectorAll('.mainitem').length;
    var scroller = d.querySelector('.scroller');
    var pos = 0;
    var transform = Modernizr.prefixed('transform');
    var currentrow = 0;
    var lastrow = 0;
    var activateLast = false;
    var dotposition = 0;

    function resizeItems() {

        //itemCount = d.querySelectorAll('.mainitem').length;
        var currentrow = Math.round((items.offsetWidth / ($('.item img').width() + 20)));
        itemCount = Math.ceil($('.item img').length / currentrow);

        onload(currentrow);

        if ($(window).width() < 568) {

            $(".detailviewlarge").css("maxWidth", ($(window).width() - 50 + "px"));
        }

    }
    resizeItems();

    $('.activedot label').click(function () {
        var dotIndex = $(this).index();
        //console.log(dotIndex);
        $('.activedot label').removeClass('active');
        $('.activedot label').eq(dotIndex).addClass('active');
        setGetParameter("video", dotIndex + 1);
        resizeItems();
        //$('#video .item').eq(dotIndex).trigger('click');

        if ($(window).width() < 568) {
            $('.showtime').removeClass('onlymob');
            $('.playWrapper').removeClass('pauseplay');
            $('.item.active .imageItem').removeClass('nodisplay');
          //  player.pause();
        }

    });

    function onload(currentrow) {
        var videocountID = getParameterByName('video');
        if (videocountID != null && parseInt(videocountID) > 0 && parseInt(videocountID) <= $('.item img').length) {
            videocountID = videocountID;
        } else {
            videocountID = 1;
        }
        dotposition = videocountID - 1;
        $('.activedot label').removeClass('active');
        $('.activedot label').eq(dotposition).addClass('active');

        if ((parseInt(currentrow * itemCount) - parseInt($('.item img').length)) > 0) {

            lastrow = currentrow * itemCount - $('.item img').length;

        } else {
            lastrow = 0;
        }
        //console.log(pos);
        pos = Math.ceil(videocountID / currentrow) - 1;
        //console.log(pos);
        prevposvalue();
        nextposvalue();
        if ((pos == itemCount - 1) && (lastrow > 0)) {
            setlastTransform();
            activateLast = true;
        } else {
            activateLast = false;
            setTransform();
        }
    }
    function setlastTransform() {

        var defaultvalue = 3;
        if ($(window).width() > 567 && $(window).width() < 768) defaultvalue = 20;
        if ($(window).width() > 639 && $(window).width() < 768) defaultvalue = 25;
        if ($(window).width() > 767 && $(window).width() < 1024) defaultvalue = 45;
        if ($(window).width() > 1023) defaultvalue = 33;

        //console.log(pos);
        //console.log(items.offsetWidth);
        //console.log(lastrow);
        //console.log($('.item').width());
        //console.log(defaultvalue);
        var translatenumber = -parseInt(pos) * parseInt(items.offsetWidth);
        translatenumber += parseInt(lastrow) * parseInt($('.item').width() + defaultvalue);
        if (translatenumber > 0) translatenumber = 0;
        items.style[transform] = 'translate3d(' + translatenumber + 'px,0,0)';

    }
    
    function setTransform() {
        var translatenum = -parseInt(pos) * parseInt(items.offsetWidth);

        if (translatenum > 0) translatenum = 0;
        items.style[transform] = 'translate3d(' + -pos * items.offsetWidth + 'px,0,0)';

    }

    function prevItem() {
        pos = Math.max(pos - 1, 0);
        $('.next').addClass('active');
        prevposvalue();
        if ((pos == 0) && (lastrow > 0)) {
            activateLast = false;

            setlastTransform();
        } else {
            if (activateLast == true) {
                setlastTransform();
            } else {
                setTransform();
            }
        }
        if ($(window).width() < 568) {
            $('.showtime').removeClass('onlymob');
            $('.playWrapper').removeClass('pauseplay');
            $('.item.active .imageItem').removeClass('nodisplay');
          //  player.pause();
            dotposition = dotposition - 1;
            $('.activedot label').removeClass('active');
            $('.activedot label').eq(dotposition).addClass('active');
        }

    }

    function prevposvalue() {
        if (pos != 0) {
            $('.previous').addClass('active');
        } else {
            $('.previous').removeClass('active');
        }
    }

    function nextItem() {
        pos = Math.min(pos + 1, itemCount - 1);
        $('.previous').addClass('active');
        nextposvalue();
        setlastTransform();
        if ((pos == itemCount - 1) && (lastrow > 0)) {
            activateLast = true;

            setlastTransform();
        } else {
            if (activateLast == true) {
                setlastTransform();
            } else {
                setTransform();
            }
        }

        //setTransform();
        if ($(window).width() < 568) {
            $('.showtime').removeClass('onlymob');
            $('.playWrapper').removeClass('pauseplay');
            $('.item.active .imageItem').removeClass('nodisplay');
            //player.pause();
            dotposition = dotposition + 1;
            $('.activedot label').removeClass('active');
            $('.activedot label').eq(dotposition).addClass('active');
        }
    }

    function nextposvalue() {
        if (pos != (itemCount - 1)) {
            $('.next').addClass('active');
        } else {
            $('.next').removeClass('active');
        }
    }

    var resizeHandler = function () {
        //videoframesize();
        resizethumbnailItems();
        resizeItems();
        try {
            if ($('.video-js').hasClass('vjs-playing')) {
                $('.showtime .showtime-body').hide();
                $('.showtime .showreal-body').show();
                if (!$('.video-js').hasClass('vjs-fullscreen') && $(window).width() > 567 && $(window).width() < 980) {
                    $('.vjs-fullscreen-control').click();
                }
                if ($(window).width() < 568) {
                  //  player.pause();
                  //  player.exitFullscreen();
                    $('html, body').animate({
                        scrollTop: $('#video').offset().top - 70
                    }, 800, function () {
                    });
                }
            } else {
              //  player.pause();
              //  player.exitFullscreen();
            }

            //player.exitFullscreen();

        } catch (err) { }
        //items.style[transform] = 'translate3d(0,0,0)';
        //setTransform();
    };

    var cachedWidth = $(window).width();
    $(window).resize(function () {
        var newWidth = $(window).width();
        if (newWidth !== cachedWidth) {
            resizeHandler();
            cachedWidth = newWidth;
        }
    });
//window.addEventListener('resize', resizeHandler);

